class Playground {
    async run(inputs) {
        const N = parseInt(inputs[0]);
        // initialise board with zeros
        const empty = Array.from({ length: N }, () => Array(N).fill(0));
        this.board.init(empty);
        // initialise helper sets
        this.cols.init([]);
        this.diag1.init([]);
        this.diag2.init([]);
        // initialise visual helpers
        this.callstack.init();
        this.recursionTree.init();
        const self = this;
        async function backtrack(row) {
            self.callstack.pushFrame('backtrack', { row });
            self.recursionTree.enterNode(`r${row}`, `row=${row}`, '#00e0ff');
            self.log(`Entering row ${row}`);
            await self.await();
            if (row === N) {
                self.log('Solution found');
                await self.await();
                self.callstack.popFrame();
                self.recursionTree.exitNode('#00f5a0');
                return true;
            }
            for (let col = 0; col < N; col++) {
                const d1 = row - col;
                const d2 = row + col;
                if (self.cols.has(col) || self.diag1.has(d1) || self.diag2.has(d2)) {
                    self.log(`Cell (${row},${col}) is unsafe`);
                    await self.await();
                    continue;
                }
                // place queen
                self.board.setCell(row, col, 1);
                self.cols.add(col);
                self.diag1.add(d1);
                self.diag2.add(d2);
                self.log(`Placed queen at (${row},${col})`);
                await self.await();
                // recurse
                if (await backtrack(row + 1)) {
                    self.callstack.popFrame();
                    self.recursionTree.exitNode('#00f5a0');
                    return true;
                }
                // backtrack removal
                self.board.setCell(row, col, 0);
                self.cols.remove(col);
                self.diag1.remove(d1);
                self.diag2.remove(d2);
                self.log(`Removed queen from (${row},${col})`);
                await self.await();
            }
            self.callstack.popFrame();
            self.recursionTree.exitNode('#ffb703');
            return false;
        }
        const found = await backtrack(0);
        if (!found) {
            this.log('No solution exists');
            await this.await();
        }
        return this.board.getValues();
    }
}
